parameters.jsCode:
const ai = $json;

const state = $('Load Runtime State').item.json;

const questions = (ai.questions || [])
  .map((q, i) => `${i + 1}. ${q}`)
  .join('\n');

const firstMessageId =
  state.runtime_state.messages?.[0]?.message_id;

const internalChatId =
  String(state.chat_id).replace('-100', '');

const messageLink =
  `https://t.me/c/${internalChatId}/${firstMessageId}`;

const messageCount =
  state.runtime_state.messages?.length || 0;

const expertMessage = `🔔 Звернення #${state.id}

<b>Група:</b>
${state.chat_title || 'Невідома група'}

<b>Користувач:</b>
${state.user_name || 'Невідомий користувач'}

<b>Telegram ID:</b>
${state.user_id}

<b>Короткий опис:</b>
${ai.topic}

<b>Питання:</b>
${questions}

<b>Посилання:</b>
<a href="${messageLink}">Відкрити повідомлення</a>

<b>Повідомлень у зверненні:</b>
${messageCount}`;

return [{
  ...state,
  ...ai,
  expert_message: expertMessage
}];

