parameters.jsCode:
const state = $('Load Runtime State').item.json;

const ai = $json.output;

const runtime = state.runtime_state || {};

runtime.analysis = {
  language: ai.language,
  topic: ai.topic,
  questions: ai.questions || [],
  needs_escalation: ai.needs_escalation,
  analyzed_at: new Date().toISOString()
};

return [{
  ...state,
  runtime_state: runtime,

  language: ai.language,
  topic: ai.topic,
  questions: ai.questions || [],
  needs_escalation: ai.needs_escalation
}];

parameters.query:
SELECT *
FROM telegram_runtime_state
WHERE id = {{ $('Parse Payload').item.json.runtime_id }}
LIMIT 1;

